SELECT conversion_rate
FROM currency_conversion
WHERE from_currency = 'USD' AND to_currency = 'HKD';

SELECT COUNT(*)
FROM financial_instruments
WHERE status = 'active';

SELECT manager_id, COUNT(portfolio_id) AS total_portfolios
FROM portfolio_management
GROUP BY manager_id;

SELECT COUNT(*) AS total_active_instruments, SUM(CAST(par_amount AS REAL)) AS total_par_amount
FROM financial_instruments
WHERE status = 'active';
